class Solution:
    def checkStraightLine(self, coordinates):
        x0, y0 = coordinates[0]
        x1, y1 = coordinates[1]
        for x, y in coordinates:
            # collinear iff the triangle area (x0,y0),(x1,y1),(x,y) is zero
            area2 = x0 * (y1 - y) + x1 * (y - y0) + x * (y0 - y1)
            if area2 != 0:
                return False
        return True

