class Solution:
    def checkStraightLine(self, coordinates):
        x0, y0 = coordinates[0]
        dx, dy = coordinates[1][0] - x0, coordinates[1][1] - y0
        for x, y in coordinates[2:]:
            if dx * (y - y0) != dy * (x - x0):
                return False
        return True

